// Save PDF attachment(s) to /tmp/n8n-invoices/
const items = $input.all();
const fs = require('fs');
const path = require('path');

const results = [];
for (const item of items) {
  const attachments = item.json.attachments || [];
  for (const attachment of attachments) {
    if (!attachment.filename?.toLowerCase().endsWith('.pdf')) continue;

    const tmpDir = '/tmp/n8n-invoices';
    if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });

    const safeName = attachment.filename.replace(/[^a-zA-Z0-9._-]/g, '_');
    const filePath = path.join(tmpDir, `${Date.now()}_${safeName}`);

    let buffer;
    if (attachment.data) {
      buffer = Buffer.from(attachment.data, 'base64');
    } else if (attachment.contentBytes) {
      buffer = Buffer.from(attachment.contentBytes, 'base64');
    } else {
      console.warn('No attachment data found for', attachment.filename);
      continue;
    }

    fs.writeFileSync(filePath, buffer);

    results.push({
      json: {
        file_path: filePath,
        source_email: item.json.from || item.json.sender,
        subject: item.json.subject,
        filename: attachment.filename,
        message_id: item.json.id
      }
    });
  }
}
return results.length > 0 ? results : [{ json: { error: 'No PDF attachments found' } }];

// Parse SOL webhook response and prepare for SQLite insert
const response = $input.first().json;

if (response.status === 'error') {
  throw new Error(`Extraction failed: ${response.message}`);
}

if (response.status !== 'success' || !response.extracted_data) {
  throw new Error('Unexpected response format from SOL webhook');
}

const data = response.extracted_data;

return [{
  json: {
    invoice_number: data.invoice_number || 'UNKNOWN',
    vendor_name: data.vendor_name || 'UNKNOWN',
    invoice_date: data.invoice_date || null,
    total_amount: typeof data.total_amount === 'number' ? data.total_amount : null,
    line_items: JSON.stringify(data.line_items || []),
    source_email: response.source_email || $input.first().json.source_email,
    file_path: response.file_path || $input.first().json.file_path,
    extraction_method: response.extraction_method || 'vision',
    extracted_at: new Date().toISOString(),
    processed: 0
  }
}];

